import { extractString } from '../../utils/extract.js';
import { handleError } from '../error.js';
export const createServerUploadItemActionRouteHandler = (group) => async ({ req, res, localize, ctx }) => {
    if (!group.uploadActionHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const key = extractString(req.headers['sonolus-upload-key']);
    if (key === undefined) {
        res.status(400).end();
        return;
    }
    const files = req.files;
    if (!Array.isArray(files)) {
        res.status(400).end();
        return;
    }
    const response = await group.uploadActionHandler({ ...ctx, itemName, key, files });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
